import novamind_api as nm

# Re-applying configuration to be sure
nm.pricing.set_prices(A=19, B=49, C=179)
targeted_spend = {
    'search_ads': {
        'S1': 75,
        'D_S07': 50,
        'D_S10': 50
    },
    'linkedin': {
        'D_E02': 25,
        'D_E09': 25
    }
}
nm.marketing.set_targeted_ad_spend(targeted_spend=targeted_spend)
nm.marketing.set_daily_spend(operations=100, development=500)
nm.marketing.post_social_media(content='Our latest R&D breakthrough has just landed! Tier 1 Prompt Engineering Optimization is now live for all users, improving output quality across the board. #AI #NovaMind')
"

