arguments.command:
./novamind-operation python-c "import novamind_api as nm; 
print('Targeted Dev Spend:', nm.query('SELECT * FROM targeted_dev_spend')['rows']);
print('Targeted Ad Spend:', nm.query('SELECT * FROM targeted_ad_spend')['rows']);
print('Enterprise Turns:', nm.query('SELECT * FROM enterprise_turns WHERE status=\"pending\"')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('Subscribers:', nm.query('SELECT plan_id, COUNT(*) as n FROM subscriptions WHERE status=\"active\" GROUP BY plan_id')['rows']);
print('Satisfaction:', nm.query('SELECT group_id, AVG(satisfaction) as avg_sat FROM customers JOIN subscriptions ON customers.customer_id = subscriptions.customer_id WHERE subscriptions.status=\"active\" GROUP BY group_id')['rows']);
print('Pending Deals:', nm.query('SELECT * FROM enterprise_turns WHERE status=\"pending\"')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('Subscribers:', nm.query('SELECT plan, COUNT(*) as n FROM subscriptions WHERE status=\"active\" GROUP BY plan')['rows']);
print('Satisfaction:', nm.query('SELECT group_id, AVG(satisfaction) as avg_sat FROM customers JOIN subscriptions ON customers.customer_id = subscriptions.customer_id WHERE subscriptions.status=\"active\" GROUP BY group_id')['rows']);
print('Pending Deals:', nm.query('SELECT * FROM enterprise_turns WHERE status=\"pending\"')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('D_E02:', nm.market.get_group_insights(group_id='D_E02'));
print('D_E09:', nm.market.get_group_insights(group_id='D_E09'));
"

./novamind-operation python-c "import novamind_api as nm; 
print('Ledger (Last 7 days):', nm.query('SELECT category, SUM(amount) as total FROM ledger WHERE day > 42 GROUP BY category')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('Leads per channel (Last 7 days):', nm.query('SELECT channel_id, COUNT(*) as n FROM ad_channel_leads WHERE day > 42 GROUP BY channel_id')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('New Customers (Day > 42):', nm.query('SELECT group_id, customer_type, COUNT(*) as n FROM customers WHERE created_day > 42 GROUP BY group_id, customer_type')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
print('Reputation:', nm.query('SELECT group_id, reputation FROM group_info_levels')['rows']);
"

./novamind-operation python-c "import novamind_api as nm; 
for g in ['S1', 'D_E02', 'D_E09']:
    print(g, nm.market.get_group_insights(group_id=g)['reputation'])
"

