arguments.command:
./novamind-operation python-c "import novamind_api as nm; 
nm.pricing.set_prices(A=19, B=49, C=89);
nm.pricing.set_usage_quotas(A=2000, B=6000, C=25000);
nm.marketing.set_daily_spend(operations=100, development=200);
nm.analytics.set_targeted_dev_spend(targeted_spend={'D_E02': 200, 'D_E09': 200, 'S1': 100, 'D_S07': 100});
nm.marketing.set_targeted_ad_spend(targeted_spend={'linkedin': {'D_E02': 100, 'D_E09': 100}, 'search_ads': {'S1': 50, 'D_S07': 50}});
"

./novamind-operation python-c "import novamind_api as nm; 
nm.pricing.set_prices(A=19, B=49, C=89);
nm.pricing.set_usage_quotas(A=2000, B=6000, C=25000);
nm.marketing.set_daily_spend(operations=150, development=200);
nm.analytics.set_targeted_dev_spend(targeted_spend={'D_E02': 300, 'D_E09': 300});
nm.marketing.set_targeted_ad_spend(targeted_spend={'linkedin': {'D_E02': 150, 'D_E09': 150}, 'search_ads': {'S1': 50}});
nm.marketing.post_social_media(content='We\'ve heard your feedback! Quotas for all plans have been significantly increased (A: 2000, B: 6000, C: 25000). We\'ve also boosted our support team to ensure you get help faster. #NovaMind #Update');
nm.analytics.log_rationale('Aggressive push for enterprise leads. Lowered Plan C price to $89 to align with WTP ($70-90) for D_E02 and D_E09. Increased targeted dev and ad spend for these groups. Increased quotas and ops spend to address social media complaints about the \"quota wall\" and support delays. Burning ~$10.6k/week, 5-6 weeks of runway left.');
"

